#include <iostream>
#include <string>
#include <vector>

int main() {
    std::ios::sync_with_stdio(false);
    std::cin.tie(nullptr);

    std::string s;
    std::cin >> s;
    int n = static_cast<int>(s.size());
    std::vector<int> left(n, 1), right(n, 1);
    for (int i = 1; i < n; ++i) {
        if (s[i] == s[i - 1]) left[i] = left[i - 1] + 1;
    }
    for (int i = n - 2; i >= 0; --i) {
        if (s[i] == s[i + 1]) right[i] = right[i + 1] + 1;
    }

    long long ans = 0;
    for (int i = 0; i + 1 < n; ++i) {
        if (s[i] + 1 == s[i + 1]) {
            // 边界左右各取同样长度，形成 d...d (d+1)...(d+1)。
            ans += std::min(left[i], right[i + 1]);
        }
    }
    std::cout << ans << '\n';
    return 0;
}

