int main() {
    std::ios::sync_with_stdio(false);
    std::cin.tie(nullptr);

    int n;
    std::cin >> n;
    std::vector<std::vector<int>> grid(n, std::vector<int>(n, 0));
    int r = 0, c = (n - 1) / 2;
    grid[r][c] = 1;
    for (int k = 2; k <= n * n; ++k) {
        int nr = (r - 1 + n) % n;
        int nc = (c + 1) % n;
        if (grid[nr][nc] == 0) {
            r = nr;
            c = nc;
        } else {
            r = (r + 1) % n;
        }
        grid[r][c] = k;
    }

    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            if (j) std::cout << ' ';
            std::cout << grid[i][j];
        }
        std::cout << '\n';
    }
    return 0;
}

