    int T;
    std::cin >> T;
    while (T--) {
        int n;
        std::cin >> n;
        std::vector<long long> cost(n);
        long long power = 0;
        for (int i = 0; i < n; ++i) {
            long long w, p;
            std::cin >> w >> p;
            power += p;
            cost[i] = w + p;
        }
        std::sort(cost.begin(), cost.end());
        int ans = 0;
        long long used = 0;
        for (long long x : cost) {
            if (used + x <= power) {
                used += x;
                ++ans;
            } else {
                break;
            }
        }
        std::cout << ans << '\n';
    }
    return 0;
}

