int main() {
    std::ios::sync_with_stdio(false);
    std::cin.tie(nullptr);

    int n, k;
    long long x;
    std::cin >> n >> k >> x;
    std::vector<long long> a(n);
    for (long long& v : a) std::cin >> v;
    std::sort(a.begin(), a.end(), std::greater<long long>());

    std::vector<long long> pref(n + 1, 0);
    for (int i = 0; i < n; ++i) pref[i + 1] = pref[i] + a[i];

    int free_water = n - k;
    for (int m = free_water + 1; m <= n; ++m) {
        int guaranteed = m - free_water;
        // 选前 m 大，最坏清酒是其中靠后的 guaranteed 个。
        long long sake = pref[m] - pref[m - guaranteed];
        if (sake >= x) {
            std::cout << m << '\n';
            return 0;
        }
    }
    std::cout << -1 << '\n';
    return 0;
}

