class Fenwick {
public:
    explicit Fenwick(int n) : bit(n + 1, 0) {}
    void add(int idx, long long val) {
        for (int i = idx; i < static_cast<int>(bit.size()); i += i & -i) bit[i] += val;
    }
    long long sum(int idx) const {
        long long res = 0;
        for (int i = idx; i > 0; i -= i & -i) res += bit[i];
        return res;
    }
private:
    std::vector<long long> bit;
};

int main() {
    std::ios::sync_with_stdio(false);
    std::cin.tie(nullptr);

    int n, q;
    std::cin >> n >> q;
    std::vector<long long> a(n + 1);
    Fenwick fw(n);
    for (int i = 1; i <= n; ++i) {
        std::cin >> a[i];
        fw.add(i, a[i]);
    }
    while (q--) {
        int type;
        std::cin >> type;
        if (type == 1) {
            int x;
            std::cin >> x;
            long long vx = a[x], vy = a[x + 1];
            std::swap(a[x], a[x + 1]);
            fw.add(x, vy - vx);
            fw.add(x + 1, vx - vy);
        } else {
            int l, r;
            std::cin >> l >> r;
            std::cout << fw.sum(r) - fw.sum(l - 1) << '\n';
        }
    }
    return 0;
}

