int main() {
    std::ios::sync_with_stdio(false);
    std::cin.tie(nullptr);

    int n;
    std::cin >> n;
    const int MAXA = 200000;
    std::vector<int> freq(MAXA + 2, 0);
    int mx = 0;
    for (int i = 0; i < n; ++i) {
        int a;
        std::cin >> a;
        ++freq[a];
        mx = std::max(mx, a);
    }

    std::vector<int> digits;
    long long cover = 0;
    long long carry = 0;
    for (int pos = mx - 1; pos >= 0; --pos) cover += freq[pos + 1];
    for (int pos = 0; pos < mx || carry > 0; ++pos) {
        if (pos > 0 && pos <= mx) cover -= freq[pos];
        long long value = cover + carry;
        digits.push_back(static_cast<int>(value % 10));
        carry = value / 10;
    }
    while (digits.size() > 1 && digits.back() == 0) digits.pop_back();
    for (auto it = digits.rbegin(); it != digits.rend(); ++it) std::cout << *it;
    std::cout << '\n';
    return 0;
}

