#include <deque>
#include <iostream>
#include <utility>
#include <vector>

int main() {
    std::ios::sync_with_stdio(false);
    std::cin.tie(nullptr);

    int T;
    std::cin >> T;
    while (T--) {
        int n, d;
        std::cin >> n >> d;
        std::vector<int> a(n + 1), b(n + 1);
        for (int i = 1; i <= n; ++i) std::cin >> a[i];
        for (int i = 1; i <= n; ++i) std::cin >> b[i];

        std::deque<std::pair<int, long long>> q;
        long long stock = 0;
        for (int day = 1; day <= n; ++day) {
            q.push_back({day, a[day]});
            stock += a[day];
            int need = b[day];
            while (need > 0) {
                int take = static_cast<int>(std::min<long long>(need, q.front().second));
                q.front().second -= take;
                need -= take;
                stock -= take;
                if (q.front().second == 0) q.pop_front();
            }
            int expire_day = day - d + 1;
            while (!q.empty() && q.front().first <= expire_day) {
                stock -= q.front().second;
                q.pop_front();
            }
        }
        std::cout << stock << '\n';
    }
    return 0;
}

#include <iostream>
#include <unordered_map>

int main() {
    std::ios::sync_with_stdio(false);
    std::cin.tie(nullptr);

    int n;
    std::cin >> n;
    std::unordered_map<long long, int> dp;
    dp.reserve(static_cast<std::size_t>(n) * 2);
    int ans = 0;
    for (int i = 0; i < n; ++i) {
        long long x;
        std::cin >> x;
        int best = 1;
        auto it = dp.find(x - 1);
        if (it != dp.end()) best = it->second + 1;
        if (dp[x] < best) dp[x] = best;
        if (ans < dp[x]) ans = dp[x];
    }
    std::cout << ans << '\n';
    return 0;
}

