std::string skeleton(const std::string& s, std::vector<int>& gaps) {
    std::string core;
    gaps.clear();
    gaps.push_back(0);
    for (char ch : s) {
        if (ch == 'A') {
            ++gaps.back();
        } else {
            core.push_back(ch);
            gaps.push_back(0);
        }
    }
    return core;
}

int main() {
    std::ios::sync_with_stdio(false);
    std::cin.tie(nullptr);

    std::string s, t;
    std::cin >> s >> t;
    std::vector<int> gs, gt;
    std::string cs = skeleton(s, gs);
    std::string ct = skeleton(t, gt);
    if (cs != ct) {
        std::cout << -1 << '\n';
        return 0;
    }
    long long ans = 0;
    for (std::size_t i = 0; i < gs.size(); ++i) {
        ans += std::llabs(static_cast<long long>(gs[i]) - gt[i]);
    }
    std::cout << ans << '\n';
    return 0;
}

