#include <iostream>
#include <string>
#include <vector>

int main() {
    std::ios::sync_with_stdio(false);
    std::cin.tie(nullptr);

    int n, L, R;
    std::string s;
    std::cin >> n >> L >> R >> s;
    std::vector<std::vector<int>> pos(26);
    for (int i = 0; i < n; ++i) pos[s[i] - 'a'].push_back(i);

    long long ans = 0;
    for (const auto& v : pos) {
        int left = 0, right = 0;
        for (int j = 0; j < static_cast<int>(v.size()); ++j) {
            while (right < j && v[j] - v[right] >= L) ++right;
            while (left < j && v[j] - v[left] > R) ++left;
            ans += right - left;
        }
    }
    std::cout << ans << '\n';
    return 0;
}
